mapper.select:
SELECT 0 AS CASE_SEQ,
       SSPS_DL_CRT_DT, SSPS_DL_ID, SSPS_TYP_CD, SSPS_DL_CRT_CCD,
       RPR_PRGRS_CCD, DL_P_RNMCNO, RSK_MRK, RSK_GRD_CD, OK_CCD,
       SCNR_MRK, AI_RESULT, REG_ID, REG_DT, UPD_ID, UPD_DT
FROM NIC66B
WHERE 1=1

    AND RPR_PRGRS_CCD = #{caseStCd}


    AND SSPS_DL_CRT_CCD = #{caseTpCd}


    AND DL_P_RNMCNO = #{custNo}


    AND REG_ID = #{assignId}

ORDER BY REG_DT DESC
LIMIT #{size} OFFSET #{offset}

SELECT COUNT(*)
FROM NIC66B
WHERE 1=1

    AND RPR_PRGRS_CCD = #{caseStCd}


    AND SSPS_DL_CRT_CCD = #{caseTpCd}


    AND DL_P_RNMCNO = #{custNo}


    AND REG_ID = #{assignId}

SELECT COUNT(*)
FROM NIC66B
WHERE RPR_PRGRS_CCD = #{caseStCd}
